500	/// derivation: `${RBRR_CLOUD_PREFIX}d-${moniker}`. Used by cases 2 and 3 to
501	/// recover the project_id post-levy without re-reading a fact file (the
502	/// pre-collapse `rbgp_fact_depot_project_id` producer is gone).
503	fn rbtdrp_compose_project_id(root: &Path, moniker: &str) -> Result<String, String> {
504	    let rbrr = root.join(RBTDRP_RBRR_FILE);
505	    let cloud_prefix = rbtdrp_read_env_value(&rbrr, RBTDRP_FIELD_RBRR_CLOUD_PREFIX)
506	        .ok_or_else(|| format!("RBRR_CLOUD_PREFIX missing from {}", rbrr.display()))?;
507	    Ok(format!("{}d-{}", cloud_prefix, moniker))
508	}
509	
510	/// Set `RBRR_DEPOT_MONIKER` in rbrr.env to `moniker` and commit. Cases 2-3
511	/// use this to install a moniker that drives `RBDC_DEPOT_PROJECT_ID` via
512	/// kindle derivation. The commit is separate from the throwaway-prefix
513	/// commit so the audit trail shows the moniker landing as its own pace.
514	fn rbtdrp_install_depot_moniker(root: &Path, moniker: &str) -> Result<(), String> {
515	    let rbrr = root.join(RBTDRP_RBRR_FILE);
516	    let content = std::fs::read_to_string(&rbrr)
517	        .map_err(|e| format!("rbtdrp: read {}: {}", rbrr.display(), e))?;
518	    let new_content = rbtdrp_replace_env_fields(
519	        &content,
520	        &[(RBTDRP_FIELD_RBRR_DEPOT_MONIKER, moniker)],
521	    );
522	    std::fs::write(&rbrr, &new_content)
523	        .map_err(|e| format!("rbtdrp: write {}: {}", rbrr.display(), e))?;
524	
525	    let commit_msg = format!(
526	        "pristine-lifecycle fixture: set {}={}",
527	        RBTDRP_FIELD_RBRR_DEPOT_MONIKER, moniker
528	    );
529	    rbtdrp_git_add_and_commit(root, RBTDRP_RBRR_FILE, &commit_msg)
530	}
531	
532	// ── Case ─────────────────────────────────────────────────────
533	
534	/// Case 1 — marshal-zero attestation. Aggregates all five violation classes
535	/// into a single diagnostic. A passing run is the proof that `rbw-MZ` was
536	/// just executed and committed.
537	fn rbtdrp_marshal_zero_attestation(_dir: &Path) -> rbtdre_Verdict {
538	    let root = match std::env::current_dir() {
539	        Ok(r) => r,
540	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot resolve project root: {}", e)),
541	    };
542	
543	    let rbrr = root.join(RBTDRP_RBRR_FILE);
544	    if !rbrr.exists() {
545	        return rbtdre_Verdict::Fail(format!("RBRR file not found: {}", rbrr.display()));
546	    }
547	
548	    let secrets_dir = rbtdrp_read_env_value(&rbrr, "RBRR_SECRETS_DIR").unwrap_or_default();
549	    let vessel_dir = rbtdrp_read_env_value(&rbrr, "RBRR_VESSEL_DIR").unwrap_or_default();
550	
551	    let mut violations: Vec<String> = Vec::new();
552	
553	    rbtdrp_check_tree_clean(&root, &mut violations);
554	    rbtdrp_check_rbrr_fields(&rbrr, &mut violations);
555	    rbtdrp_check_rbra_files(&root, &secrets_dir, &mut violations);
556	    rbtdrp_check_nameplate_hallmarks(&root, &mut violations);
557	    rbtdrp_check_vessel_depot_fields(&root, &vessel_dir, &mut violations);
558	
559	    if violations.is_empty() {
560	        return rbtdre_Verdict::Pass;
561	    }
562	
563	    let body = violations
564	        .iter()
565	        .map(|v| format!("  - {}", v))
566	        .collect::<Vec<_>>()
567	        .join("\n");
568	    rbtdre_Verdict::Fail(format!(
569	        "marshal-zero attestation failed — {} violation(s):\n{}\n\n\
570	         remedy: tt/rbw-MZ.MarshalZeroes.sh, then commit and rerun.",
571	        violations.len(),
572	        body
573	    ))
574	}
